class="pay-method"
:class="{
  selected: selectedPaymentMethod === 'wallet',
  disabled: walletBalance < cartTotal - productDiscount,
}"

font-family: "Dancing Script", cursive;
font-size: 3rem;
margin-bottom: 1.5rem;
color: #3e2723;

const {
              ctx,
              chartArea: { left, right },
              scales: { y },
            } = chart;

ctx.quadraticCurveTo(
  rectX + rectW,
  rectY,
  rectX + rectW,
  rectY + radius
);

ctx.quadraticCurveTo(
  rectX + rectW,
  rectY + h,
  rectX + rectW - radius,
  rectY + h
);

ctx.quadraticCurveTo(
  rectX,
  rectY + h,
  rectX,
  rectY + h - radius
);
